commands.examples:
SELECT NOW();
SELECT CURRENT_DATE;
SELECT CURRENT_TIMESTAMP;
SELECT CLOCK_TIMESTAMP();

SELECT EXTRACT(YEAR FROM NOW());
SELECT EXTRACT(MONTH FROM '2024-06-15'::DATE);
SELECT DATE_PART('dow', CURRENT_DATE);
SELECT EXTRACT(EPOCH FROM NOW());
SELECT EXTRACT(EPOCH FROM INTERVAL '1 day'); -- 86400

SELECT DATE_TRUNC('month', NOW()); -- 2024-06-01 00:00:00
SELECT DATE_TRUNC('hour', NOW());

-- Statistik bulanan
SELECT DATE_TRUNC('month', created_at) AS month, COUNT(*)
FROM orders GROUP BY 1 ORDER BY 1;

SELECT TO_CHAR(NOW(), 'DD/MM/YYYY HH24:MI');
SELECT TO_CHAR(NOW(), 'Day, DD Month YYYY');
SELECT TO_DATE('15-06-2024', 'DD-MM-YYYY');
SELECT TO_TIMESTAMP('2024-06-15 14:30:00', 'YYYY-MM-DD HH24:MI:SS');

SELECT NOW() + INTERVAL '30 days';
SELECT NOW() - INTERVAL '2 hours';
SELECT NOW() + INTERVAL '1 year 3 months';

-- Data 7 hari terakhir
SELECT * FROM orders WHERE created_at > NOW() - INTERVAL '7 days';
